var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 일대의 침식체는 정리가 끝난 것 같군. 복귀하겠다.","JPN":"ここ一体の侵食体は、すべて片付いたようだ。これより、帰投する。","ENG":"Looks like we cleared out all C.O. in this area. We're heading back.","TWN":"這一帶的侵蝕體好像都被清除得差不多了，準備歸隊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"레이더에도 침식파는 검출되지 않습니다.","JPN":"レーダーからも侵食波は感知されません。","ENG":"There are no signs of Corruption Rays on the radar either.","TWN":"雷達也沒有偵測出侵蝕波。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"도시 경비대에 보고하는 건 제가 할게요. 수고하셨습니다.","JPN":"都市警備隊への報告は私に任せてください。お疲れ様でした。","ENG":"I'll inform the city guards. Good work.","TWN":"我來向城市守衛報告。辛苦了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......알겠다. 교신 종료.","JPN":"……了解。交信終了。","ENG":"Roger that. Over and out.","TWN":"……知道了，通訊結束。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런데 알트 소대장. 하나 물어 보고 싶은 게 있는데.","JPN":"ところで、アオイ・シズカ小隊長。一つ聞きたいことがあるのだが。","ENG":"So, ALT Commander. I wanted to ask you something.","TWN":"話說……阿爾特小隊長，我有件事想問妳。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"무슨 일이세요, 펜릴 소대장님?","JPN":"何でしょうか、ヒルデ小隊長？","ENG":"What is it, Fenrir Commander?","TWN":"什麼事，芬里爾隊長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아침부터 소대원들 상태가 나빠 보여.","JPN":"朝からずっと、隊員たちの調子が悪そうだ。","ENG":"I noticed in the morning that your squad isn't looking too good.","TWN":"從早上開始，你們隊員們的狀態看起來就不太好。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"특히...... 안색이 초췌한 게 몇 끼나 굶은 사람들 같은데......","JPN":"特に……あのげっそりした顔を見るに、かなり腹を空かせているようだが……","ENG":"Especially... the ones that look like they've been starving for a while...","TWN":"特別是……臉色都很憔悴，看起來就像是餓了好幾頓的人一樣……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"연봉 협상 때문에 단식 투쟁이라도 하는 건가?","JPN":"年俸交渉のために断食をしてるのか？","ENG":"Are you on a hunger strike for the salary negotiation?","TWN":"難道是為了薪資協商，打算用絕食來抗爭嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 그런 건 아니고요......","JPN":"あ、そういうわけではありません……","ENG":"Uh, not exactly...","TWN":"啊，不是那樣的……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"으...... 안 돼...... 배고파서 힘이 안 나......","JPN":"うう……ダメだ……腹が減って力が出ない……","ENG":"Ugh... No... I'm so hungry I can't even move...","TWN":"呃……不行了……太餓沒力氣了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장, 우리 삼각김밥이라도 사 먹자......","JPN":"隊長、おにぎりでも買って食おうぜ……","ENG":"Cap, can we at least get some snacks from the convenience store?","TWN":"隊長，我們買點飯糰吃吧……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장...... 나도 이번에 새로 나온 레이저 스코프를 사고 싶은데......","JPN":"隊長……私も、新しく発売したレーザースコープを買いたいのだけど……","ENG":"Cap... I really want to buy the newly released laser scope...","TWN":"隊長……我想買一個新推出的鐳射瞄準鏡……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"나도 그렇고 싶지만 팀 재정은 소빈이가 관리하고 있잖아.","JPN":"私もそうしたいけど、チーム予算はコハルが管理してるから。","ENG":"I want to do all that too, but Sobin is in charge of our money.","TWN":"我也想幫你們買啊，但小隊財政不都是素蘋在管理嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런 일은 소빈이에게 부탁해야지?","JPN":"コハルに頼んでくれない？","ENG":"So you should go ask Sobin about those.","TWN":"那種事得拜託素蘋吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 야...... 아니, 저기, 소빈아......","JPN":"お、おい……いや、えっと、コハル……","ENG":"Hey, hey... No, I mean, Sobin...","TWN":"喂，喂……不對，那個，素蘋……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그...... 내가 잘못했다! 이제부터 멸치랑은 몰래 싸울게!","JPN":"その……俺が悪かった！これからは、イワシと隠れてケンカする！","ENG":"Uh... I'm so sorry! I'll fight with that Weak Sauce out of sight!","TWN":"那個……是我不對！我以後會和小魚乾偷偷吵架的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};